FUNCTION ReassembleDatagram(fragments):
 // Wait for all fragments (MF=0 indicates last)
 // Use Identification to group fragments of same datagram

 datagram = New Datagram()

 // Sort fragments by Fragment Offset
 SortFragmentsByOffset(fragments)

 // Verify no overlap and continuity
 expectedOffset = 0
 FOR EACH fragment IN fragments:
 IF fragment.Offset != expectedOffset:
 // Missing fragment(s) - discard or wait
 RETURN ERROR // Fragment loss
 END IF

 AppendData(datagram.data, fragment.data)
 expectedOffset = fragment.Offset + (fragment.TotalLength - IP_HEADER_SIZE)/8
 END FOR

 // Set final header values
 datagram.header = fragments[0].header
 datagram.header.TotalLength = Length(datagram.data) + IP_HEADER_SIZE
 datagram.header.FragmentOffset = 0
 datagram.header.MF = 0
 datagram.header.HeaderChecksum = CalculateChecksum(datagram.header)

 RETURN datagram

// Timeout handling
FUNCTION HandleReassemblyTimeout(fragmentList):
 // If all fragments not received within timeout, discard
 // Send ICMP Time Exceeded if needed
 DiscardAllFragments(fragmentList)

// Assume packet[] contains raw IPv4 packet bytes
FUNCTION ParseIPv4Header(packet):
 header = New IPv4Header()

 // Byte 0: Version (4 bits) + IHL (4 bits)
 version = (packet[0] >> 4) AND 0x0F
 ihl = packet[0] AND 0x0F
 header.Version = version
 header.HeaderLength = ihl * 4 // Convert to bytes

 // Byte 1: TOS
 header.TOS = packet[1]

 // Bytes 2-3: Total Length (16 bits, network byte order)
 header.TotalLength = (packet[2] << 8) OR packet[3]

 // Bytes 4-5: Identification
 header.Identification = (packet[4] << 8) OR packet[5]

 // Bytes 6-7: Flags (3 bits) + Fragment Offset (13 bits)
 flagsFragment = (packet[6] << 8) OR packet[7]
 header.Flags = (flagsFragment >> 13) AND 0x07
 header.FragmentOffset = flagsFragment AND 0x1FFF

 // Byte 8: TTL
 header.TTL = packet[8]

 // Byte 9: Protocol
 header.Protocol = packet[9]

 // Bytes 10-11: Header Checksum
 header.HeaderChecksum = (packet[10] << 8) OR packet[11]

 // Bytes 12-15: Source IP Address
 header.SourceIP = FormatIP(packet[12], packet[13], packet[14], packet[15])

 // Bytes 16-19: Destination IP Address
 header.DestinationIP = FormatIP(packet[16], packet[17], packet[18], packet[19])

 RETURN header
